PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT (SUM(?games) AS ?totalGames)
WHERE {
  ?series wdt:P31 wd:Q1363275 .
  {
    ?series wdt:P1346 wd:Q334634 .
    ?series wdt:P6271 wd:Q650840 .
  }
  UNION
  {
    ?series wdt:P1346 wd:Q650840 .
    ?series wdt:P6271 wd:Q334634 .
  }
  ?series wdt:P1350 ?games .
}

